// ── Query Helpers ──

export function getImagesByRoom(room: RoomType): MediaImage[] {
  return mediaLibrary.filter((img) => img.rooms.includes(room));
}

export function getImagesByProduct(product: ProductType): MediaImage[] {
  return mediaLibrary.filter((img) => img.products.includes(product));
}

export function getImagesByProject(project: ProjectType): MediaImage[] {
  return mediaLibrary.filter((img) => img.projects.includes(project));
}

export function getImagesByContext(context: ContextType): MediaImage[] {
  return mediaLibrary.filter((img) => img.contexts.includes(context));
}

export function getImagesByTag(tag: string): MediaImage[] {
  const lowerTag = tag.toLowerCase();
  return mediaLibrary.filter((img) =>
    img.tags.some((t) => t.toLowerCase().includes(lowerTag))
  );
}

export function getImageById(id: string): MediaImage | undefined {
  return mediaLibrary.find((img) => img.id === id);
}

export function getBestImage(filters: {
  room?: RoomType;
  product?: ProductType;
  project?: ProjectType;
  context?: ContextType;
}): MediaImage | undefined {
  return mediaLibrary.find((img) => {
    if (filters.room && !img.rooms.includes(filters.room)) return false;
    if (filters.product && !img.products.includes(filters.product)) return false;
    if (filters.project && !img.projects.includes(filters.project)) return false;
    if (filters.context && !img.contexts.includes(filters.context)) return false;
    return true;
  });
}
